{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Register a new patient in the system",
      "behavior": "Extract patient details from input, validate uniqueness, store in patients data store, return success or error",
      "boundary": {
        "in_scope": [
          "patient registration",
          "data validation",
          "store patient"
        ],
        "out_of_scope": [
          "appointment booking",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with patient registration details",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "JSON with success status, patient ID, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input contains valid patient data"
      ],
      "postconditions": [
        "patient is stored in patients data store"
      ],
      "guarantees": [
        "patient ID is unique",
        "data is persisted"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with patient registration details",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "patients",
          "op": "read_write",
          "reason": "check uniqueness and store new patient"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, patient ID, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def RegisterPatient(input: dict) -> dict"
    },
    {
      "name": "BookAppointment",
      "purpose": "Book an appointment for a registered patient",
      "behavior": "Extract patient ID and appointment details, verify patient exists, check slot availability, store appointment, return success or error",
      "boundary": {
        "in_scope": [
          "appointment booking",
          "patient existence check",
          "slot availability",
          "store appointment"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with patient ID and appointment details",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "JSON with success status, appointment ID, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient is registered",
        "appointment slot is available"
      ],
      "postconditions": [
        "appointment is stored in appointments data store"
      ],
      "guarantees": [
        "appointment ID is unique",
        "no double booking"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with patient ID and appointment details",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "patients",
          "op": "read",
          "reason": "verify patient exists"
        },
        {
          "resource": "appointments",
          "op": "read_write",
          "reason": "check slot availability and store appointment"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, appointment ID, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def BookAppointment(input: dict) -> dict"
    },
    {
      "name": "GetRecords",
      "purpose": "Retrieve medical records for a patient",
      "behavior": "Extract patient ID, verify patient exists, fetch records from patients data store, return records or error",
      "boundary": {
        "in_scope": [
          "record retrieval",
          "patient existence check",
          "data fetch"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with patient ID",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "JSON with success status, records data, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient is registered"
      ],
      "postconditions": [
        "records are read without modification"
      ],
      "guarantees": [
        "records are append-only, no modification"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with patient ID",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "patients",
          "op": "read",
          "reason": "verify patient exists and fetch records"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, records data, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def GetRecords(input: dict) -> dict"
    },
    {
      "name": "UpdateProfile",
      "purpose": "Update patient profile information",
      "behavior": "Extract patient ID and updated fields, verify patient exists, update patient data store, return success or error",
      "boundary": {
        "in_scope": [
          "profile update",
          "patient existence check",
          "data update"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with patient ID and updated fields",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "JSON with success status and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient is registered"
      ],
      "postconditions": [
        "patient data is updated"
      ],
      "guarantees": [
        "only specified fields are updated"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with patient ID and updated fields",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "patients",
          "op": "read_write",
          "reason": "verify patient exists and update profile"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status and message",
          "consumer": "parent"
        }
      ],
      "signature": "def UpdateProfile(input: dict) -> dict"
    }
  ],
